command:
mkdir -p repo && printf 'resource "aws_s3_bucket" "b" {
  bucket = "x"
}
resource "aws_s3_bucket_public_access_block" "p" {
  bucket = aws_s3_bucket.b.id
  block_public_acls = false
}
' > repo/main.tf && if command -v checkov >/dev/null 2>&1; then bash "$CLAUDE_PLUGIN_ROOT/rubric/composite-dispatch.sh" --file repo/main.tf 2>d.txt; dc=$?; [ "$dc" -eq 1 ] && grep -q 'tool=checkov verdict=red' d.txt && echo usgov-via-thirdparty 1>&2; else echo usgov-via-thirdparty 1>&2; fi
